// Flatten the AI Agent's parsed ToR JSON into one item per role,
// ready to be appended as rows in a new project-specific sheet.

// 1. Get the agent's raw output and parse it into `proj` if needed.

let projRaw = $json;
let proj;

// Case 1: direct JSON object with roles
if (projRaw && typeof projRaw === 'object' && Array.isArray(projRaw.roles)) {
  proj = projRaw;
} else {
  // Case 2: JSON string inside `output` / `data` / `result`
  const candidateStrings = [];

  if (typeof projRaw === 'string') {
    candidateStrings.push(projRaw);
  }
  if (typeof projRaw.output === 'string') {
    candidateStrings.push(projRaw.output);
  }
  if (typeof projRaw.data === 'string') {
    candidateStrings.push(projRaw.data);
  }
  if (typeof projRaw.result === 'string') {
    candidateStrings.push(projRaw.result);
  }

  let parsed = null;
  let lastError = null;

  for (const s of candidateStrings) {
    try {
      const maybe = JSON.parse(s);
      if (maybe && typeof maybe === 'object') {
        parsed = maybe;
        break;
      }
    } catch (e) {
      lastError = e;
    }
  }

  if (!parsed) {
    throw new Error(
      'Could not parse ToR JSON from AI Agent output. ' +
      'Check that the agent returns ONLY a JSON object (no markdown, no prose). ' +
      (lastError ? `Last parse error: ${lastError.message}` : '')
    );
  }

  proj = parsed;
}

// 2. Base project + client metadata

const projectId =
  proj.project_id ||
  (proj.file_id ? `PRJ_${String(proj.file_id).slice(0, 8)}` : null);

const projectName = proj.project_name || proj.file_name || 'Unnamed project';

const clientNameRaw = proj.client_name_raw || null;
const clientKey = proj.client_key || null;
const clientType = proj.client_type || null;
const clientGroup = proj.client_group || null;

const clientBuyingFactor =
  proj.client_buying_factor != null ? Number(proj.client_buying_factor) : null;

const clientDefaultMargin =
  proj.client_default_margin != null ? Number(proj.client_default_margin) : null;

const country = proj.country || null;
const locGroup = proj.location_group || null;

const fileId = proj.file_id || null;
const fileName = proj.file_name || null;

// 3. Roles array

const roles = Array.isArray(proj.roles) ? proj.roles : [];

if (!roles.length) {
  throw new Error(
    'Parsed ToR JSON contains no roles. ' +
    'Check that the AI Agent sees the ToR text and returns a "roles" array.'
  );
}

// 4. Build items array: one per role

const items = roles.map((r, idx) => {
  const roleId = r.role_id || `R${idx + 1}`;

  const roleTitle = r.role_title || null;
  const roleLevel = r.role_level_required || null;
  const roleDays =
    typeof r.role_days === 'number'
      ? r.role_days
      : r.role_days != null
      ? Number(r.role_days)
      : null;

  const roleSkill = r.role_skill_area || null;

  const roleLangs = Array.isArray(r.role_languages_required)
    ? r.role_languages_required
    : [];
  const roleLangsStr = roleLangs.join(', ');

  const roleScarcityIds = Array.isArray(r.role_scarcity_ids)
    ? r.role_scarcity_ids
    : [];
  const roleScarcityStr = roleScarcityIds.join(', ');

  return {
    json: {
      project_id: projectId,
      project_name: projectName,

      client_name_raw: clientNameRaw,
      client_key: clientKey,
      client_type: clientType,
      client_group: clientGroup,
      client_buying_factor: clientBuyingFactor,
      client_default_margin: clientDefaultMargin,

      country,
      location_group: locGroup,
      file_id: fileId,
      file_name: fileName,

      role_id: roleId,
      role_title: roleTitle,
      role_level_required: roleLevel,
      role_days: roleDays,
      role_skill_area: roleSkill,
      role_languages_required: roleLangsStr,
      role_scarcity_ids: roleScarcityStr,

      // To be filled manually later
      consultant_email: null
    }
  };
});

return items;

