      calc_sell_rate: "",                   // buy * (1 + margin)
      calc_days: "",                        // role_days parsed numeric
      calc_budget_buy_total: "",            // buy * days
      calc_budget_sell_total: "",           // sell * days
      calc_margin_abs: "",                  // sell_total - buy_total
      calc_margin_pct_realized: ""          // margin_abs / sell_total
    }
  }
];

// Attach the newly created sheetId from "Create sheet"
// to each role item produced by "Code in JavaScript".

// sheet info: current input (from Create sheet)
const sheetInfo = $json;
const sheetId = $('Create sheet').first().json.sheetId;

// all role items from the flattening node
const roleItems = $items('Code in JavaScript');

if (!roleItems.length) {
  throw new Error('No role items found from "Code in JavaScript".');
}

// For each role, add sheetId
const out = roleItems.map(item => {
  return {
    json: {
      ...item.json,
      sheetId
    }
  };
});

return out;

/**
 * Build Project Index Row
 * -----------------------
 * Input: the first role item (all have project_id, project_name, file_name, file_id, sheetId)
 * Output: one item for Project_Index
 */

// get first role item (each has project metadata)
const item = $json;

// required fields
const project_id   = item.project_id;
const project_name = item.project_name;
const file_id      = item.file_id;
const file_name    = item.file_name;
const sheet_id     = item.sheetId;
const sheet_name   = `Team1_${file_name}`;
const now          = new Date().toISOString();

// output ONE row
return [
  {
    json: {
      project_id,
      project_name,
      file_id,
      file_name,
      sheet_id,
      sheet_name,
      status: "ACTIVE",
      created_at: now,
      last_shortlist_run_at: ""
    }
  }
];
